const fs = require('fs');
const path = require('path');
const _ = require('lodash');

const Common = new (require('./common'));

const builderConfig = require(path.join(__dirname, '../../config.js'));

/**
 *
 */
class Config{

    constructor(){

        this.builder = builderConfig;
        this.app = _getAppConfig.call(this);
        this.env = _getEnvConfig.call(this);
    }

    /**
     *
     * @param config
     * @returns {Config}
     */
    merge(config = {}){

        _.merge(builderConfig, config);

        return this;
    }
}

/**
 * (빌더에서 사용될)각 config 값을 반환한다.
 * @returns {*}
 * @private
 */
function _getAppConfig(){

    const args = Common.getEnvArgs();
    const builderPath = this.builder.path;

    const configPath = path.join(builderPath.root, `config/${args.config}`);

    return fs.existsSync(configPath) ? require(configPath) : {};
}

/**
 * (target 변수로 사용될)env config 값을 반환한다.
 * @returns {*}
 * @private
 */
function _getEnvConfig(){

    const builderPath = this.builder.path;
    const environment = this.app.environment;

    const envPath = path.join(builderPath.env, environment);

    return fs.existsSync(envPath) ? require(envPath) : {};
}

module.exports = Config;
